import { captureEvent } from "../common/analytics/lib.js";
import { identify } from "../common/middleware/user-identification.js";
import { validatePort } from "../common/validators/argument-validators.js";
import { ZuploProjectValidator } from "../common/validators/file-system-validator.js";
import { YargsChecker } from "../common/validators/lib.js";
import { dev } from "../dev/handler.js";
export default {
    desc: "Runs the Zuplo API locally",
    command: "dev",
    builder: (yargs) => {
        return yargs
            .usage("$0 dev [options]")
            .option("dir", {
            type: "string",
            describe: "The directory containing your Zuplo API",
            default: ".",
            normalize: true,
            hidden: true,
        })
            .option("start-editor", {
            type: "boolean",
            describe: "Start the editor with the local server",
            default: true,
        })
            .option("port", {
            type: "number",
            describe: "The port to run the local server on",
            default: 9000,
        })
            .option("editor-port", {
            type: "number",
            describe: "The port to run the route designer on",
            default: 9100,
        })
            .option("start-docs", {
            type: "boolean",
            describe: "Start the docs server with the local development setup",
            default: true,
        })
            .option("docs-port", {
            type: "number",
            describe: "The port to run the docs server on",
            default: 9200,
        })
            .option("debug-port", {
            type: "number",
            describe: "The port to run the Chrome inspector on",
        })
            .option("unsafely-ignore-certificate-errors", {
            type: "boolean",
            describe: "Unsafely ignore certificate errors",
            default: false,
        })
            .example([
            [
                "$0 dev",
                "Start the local development server with default settings (port 9000 for API, port 9100 for editor, port 9200 for docs)",
            ],
            ["$0 dev --port 8080", "Start the local server on a custom port"],
            [
                "$0 dev --no-start-editor",
                "Start only the API server without opening the editor",
            ],
            [
                "$0 dev --no-start-docs",
                "Start the API server without the docs server",
            ],
            [
                "$0 dev --debug-port 9229",
                "Start with Chrome DevTools inspector enabled on port 9229",
            ],
        ])
            .middleware([identify])
            .check(async (argv) => {
            validatePort(argv.port, "--port");
            validatePort(argv["editor-port"], "--editor-port");
            validatePort(argv["docs-port"], "--docs-port");
            if (argv["debug-port"] !== undefined) {
                validatePort(argv["debug-port"], "--debug-port");
            }
            return await new YargsChecker(new ZuploProjectValidator()).check(argv);
        });
    },
    handler: async (argv) => {
        await captureEvent({
            argv,
            properties: {
                "debug-port": argv["debugPort"],
                "unsafely-ignore-certificate-errors": argv["unsafelyIgnoreCertificateErrors"],
            },
            event: "zuplo dev",
        });
        await dev(argv);
    },
};
